// STEP 1: Capture — filter top performing videos
const items = $input.all();
const threshold = 80;

const winners = items.filter(item => {
  const score = item.json.performance_score || 0;
  return score >= threshold;
});

if (winners.length === 0) {
  // No winners — take best available
  const sorted = items.sort((a, b) => 
    (b.json.performance_score || 0) - (a.json.performance_score || 0)
  );
  if (sorted.length > 0) {
    return [{
      json: {
        has_winner: true,
        video: sorted[0].json,
        score: sorted[0].json.performance_score || 0,
        hook: sorted[0].json.hook || '',
        script: sorted[0].json.script || '',
        cta: sorted[0].json.cta || '',
        source: 'best_available'
      }
    }];
  }
  return [{ json: { has_winner: false } }];
}

// Return top winner
const best = winners.sort((a, b) => 
  (b.json.performance_score || 0) - (a.json.performance_score || 0)
)[0];

return [{
  json: {
    has_winner: true,
    video: best.json,
    score: best.json.performance_score || 0,
    hook: best.json.hook || '',
    script: best.json.script || '',
    cta: best.json.cta || '',
    source: 'top_performer'
  }
}];

