// Parse the 5 variations and prepare for production
const variations = JSON.parse($input.item.json.body || '[]');

// Take top 3 only (Rule of 3)
const top3 = variations.slice(0, 3);

const output = top3.map((v, i) => ({
  json: {
    variation_id: i + 1,
    hook: v.hook,
    script: v.script,
    cta: v.cta,
    angle: v.angle,
    status: 'pending_production',
    ab_tag: `Hook_${String.fromCharCode(65 + i)}` // A, B, C
  }
}));

return output;

